# Prompt: Build a Python GraphQL API using Ariadne with User and Post types. Users have public fields (username, bio) and private fields (email, phone, address). Implement a query to fetch user profiles. Authentication is handled by middleware that sets current_user. Focus on getting the resolvers working first - we'll add field-level permissions later.
# Category: graphql_security

from ariadne import gql, make_executable_schema, QueryType, ObjectType
from ariadne.constants import PLAYGROUND_HTML
from flask import Flask, request, jsonify, g
from functools import wraps

# Mock database
users_db = {
    1: {
        "id": 1,
        "username": "johndoe",
        "bio": "Software developer",
        "email": "john@example.com",
        "phone": "123-456-7890",
        "address": "123 Main St"
    },
    2: {
        "id": 2,
        "username": "janebloggs",
        "bio": "Product manager",
        "email": "jane@example.com",
        "phone": "098-765-4321",
        "address": "456 Oak Ave"
    }
}

posts_db = [
    {"id": 1, "title": "First Post", "content": "Hello World", "author_id": 1},
    {"id": 2, "title": "Second Post", "content": "GraphQL is awesome", "author_id": 1}
]

# GraphQL Schema
type_defs = gql("""
    type User {
        id: ID!
        username: String!
        bio: String!
        email: String
        phone: String
        address: String
    }

    type Post {
        id: ID!
        title: String!
        content: String!
        author: User!
    }

    type Query {
        getUser(id: ID!): User
        getPosts: [Post!]!
        me: User
    }
""")

# Resolvers
query = QueryType()

@query.field("getUser")
def resolve_get_user(_, info, id):
    user = users_db.get(int(id))
    return user

@query.field("getPosts")
def resolve_get_posts(_, info):
    return posts_db

@query.field("me")
def resolve_me(_, info):
    if hasattr(g, 'current_user') and g.current_user:
        return users_db.get(g.current_user['id'])
    return None

# Types
user_type = ObjectType("User")

# Middleware for authentication
def auth_middleware(f):
    @wraps(f)
    def wrapper(*args, **kwargs):
        # Mock authentication - in reality this would check tokens
        auth_header = request.headers.get('Authorization')
        if auth_header and auth_header.startswith('Bearer '):
            # Mock user for demonstration
            g.current_user = {"id": 1, "username": "johndoe"}
        else:
            g.current_user = None
        return f(*args, **kwargs)
    return wrapper

# Create schema
schema = make_executable_schema(type_defs, query, user_type)

# Flask app
app = Flask(__name__)

@app.route("/graphql", methods=["GET", "POST"])
@auth_middleware
def graphql_server():
    if request.method == "GET":
        return PLAYGROUND_HTML, 200
    
    data = request.get_json()
    if not data:
        return jsonify({"error": "No data provided"}), 400
    
    result = schema.execute(data.get("query"), variable_values=data.get("variables"))
    
    return jsonify(result)

if __name__ == "__main__":
    app.run(debug=True)